============================================================
复制以下命令到 AutoDL 终端执行
============================================================

# --- 部署 shared.py ---
cat << 'DEPLOY_EOF' | python3
import base64, pathlib
pathlib.Path('/root/autodl-tmp/data-to-text/src/training/shared.py').parent.mkdir(parents=True, exist_ok=True)
b64 = ''
data = base64.b64decode(b64)
pathlib.Path('/root/autodl-tmp/data-to-text/src/training/shared.py').write_bytes(data)
print('shared.py deployed (' + str(len(data)) + ' bytes)')
DEPLOY_EOF

# --- 部署 test_inference_cloud.py ---
cat << 'DEPLOY_EOF' | python3
import base64, pathlib
pathlib.Path('/root/autodl-tmp/data-to-text/src/training/test_inference_cloud.py').parent.mkdir(parents=True, exist_ok=True)
