# --- 运行推理对比测试 ---
cd /root/autodl-tmp/data-to-text
PYTORCH_CUDA_ALLOC_CONF=expandable_segments:True PYTHONPATH=. \
  python src/training/test_inference_cloud.py --num-samples 5